mapper.select:
SELECT * FROM ( SELECT ROWNUM AS RNUM, T1.* FROM ( SELECT BOARD_NO, BOARD_TITLE, USER_NAME AS BOARD_WRITER, B.VIEW_COUNT, BOARD_DATE FROM BOARD_POST B LEFT JOIN MEMBER M ON B.USER_NO = M.USER_NO WHERE B.BOARD_DELETE = 'N'
AND BOARD_CD_NO IN (2, 3)
AND BOARD_CD_NO = #{boardCdNo}
AND
BOARD_TITLE LIKE '%' || #{keyword} || '%' USER_NAME LIKE '%' || #{keyword} || '%' BOARD_CONTENT LIKE '%' || #{keyword} || '%' (BOARD_TITLE LIKE '%' || #{keyword} || '%' OR BOARD_CONTENT LIKE '%' || #{keyword} || '%')
ORDER BY BOARD_NO DESC ) T1 ) WHERE RNUM BETWEEN #{offset} AND #{limit}
